#include "mix_kernels_cpu.h"

#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct alignas(4) half2 {
  uint16_t x;
  uint16_t y;
};

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <class T>
inline bool equal(const T a, const T b) {
  return b == a;
}

template <>
inline half2 conv_int<half2>(const int i) {
  half2 h;
  h.x = static_cast<uint16_t>(i);
  h.y = static_cast<uint16_t>(i);
  return h;
}

template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  const int16_t ax = static_cast<int16_t>(a.x);
  const int16_t ay = static_cast<int16_t>(a.y);
  const int16_t bx = static_cast<int16_t>(b.x);
  const int16_t by = static_cast<int16_t>(b.y);
  const int16_t cx = static_cast<int16_t>(c.x);
  const int16_t cy = static_cast<int16_t>(c.y);

  half2 out;
  out.x = static_cast<uint16_t>(static_cast<int16_t>(ax * bx + cx));
  out.y = static_cast<uint16_t>(static_cast<int16_t>(ay * by + cy));
  return out;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return (a.x == b.x) && (a.y == b.y);
}

template <class T, int blockdim, unsigned int granularity, unsigned int fusion_degree,
          unsigned int compute_iterations, bool TemperateUnroll>
static void benchmark_func_cpu(T seed, T* g_data, long total_blocks) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const long stride = blockSize;
  const long big_stride = total_blocks * blockSize * granularity;
  const long total_threads = total_blocks * blockSize;

#pragma omp parallel for schedule(static)
  for (long tid = 0; tid < total_threads; ++tid) {
    const long blockIdx = tid / blockSize;
    const long threadIdx = tid % blockSize;
    const long idx = blockIdx * blockSize * granularity + threadIdx;

    T tmps[granularity];
    for (unsigned int k = 0; k < fusion_degree; k++) {
      for (unsigned int j = 0; j < granularity; j++) {
        tmps[j] = g_data[idx + j * stride + static_cast<long>(k) * big_stride];

        for (unsigned int i = 0; i < compute_iterations; i++) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<long>(k) * big_stride] = sum;
      }
    }
  }
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS = static_cast<int>(reduced_grid_size / BLOCK_SIZE);

  benchmark_func_cpu<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      static_cast<short>(1), reinterpret_cast<short*>(cd), TOTAL_REDUCED_BLOCKS);
}

